#!/bin/sh
# cargo-loco-generate/cargo-loco-generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding genetic-assessment (6 tables)..."

cargo loco generate scaffold patient \
    deleted_at:ts \
    name:string! \
    birth_date:date \
    united_kingdom_nhs_number:string^ \
    waist_as_cm:double \
    height_as_cm:double \
    weight_as_kg:double \
    body_mass_index:double \
    waist_height_ratio:double \
    vo2_max:double \
    --htmx && \
cargo loco generate scaffold clinician \
    deleted_at:ts \
    name:text! \
    role:text! \
    registration_body:text! \
    registration_number:text! \
    united_kingdom_nhs_number:string^ \
    --htmx && \
cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    family_cancer_history:string! \
    multiple_family_cancers:string! \
    early_onset_cancer:string! \
    bilateral_cancer:string! \
    rare_tumour_types:string! \
    rare_tumour_details:text! \
    known_cancer_syndrome:string! \
    cancer_syndrome_details:text! \
    cancer_risk_score:int \
    cancer_history:references \
    relative_relationship:string! \
    cancer_type:string! \
    age_at_diagnosis:int \
    outcome:string! \
    sort_order:int! \
    total_first_degree_relatives:int \
    total_second_degree_relatives:int \
    consanguinity_in_family:string! \
    consanguinity_details:text! \
    adoption_status:string! \
    pedigree_notes:text! \
    three_generation_pedigree_drawn:string! \
    family_pedigree:references \
    relationship:string! \
    sex:string! \
    age:int \
    alive:string! \
    age_at_death:int \
    cause_of_death:string! \
    medical_conditions:text! \
    family_pedigree_member_sort_order:int! \
    --htmx && \
cargo loco generate scaffold grading_result \
    assessment:references \
    risk_level:string! \
    total_risk_score:int! \
    cancer_genetics_score:int! \
    cardiovascular_genetics_score:int! \
    neurogenetics_score:int! \
    reproductive_genetics_score:int! \
    graded_at:ts! \
    --htmx && \
cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    risk_level:string! \
    --htmx && \
cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
